// Extract report type and rename binary field from 'file' to 'data'
const reportType = $input.first().json.query?.report_type || $input.first().json.headers?.['x-report-type'];

if (!reportType) {
  throw new Error('Missing report_type parameter');
}

const configs = {
  accounts_payable: {
    rawTable: 'raw.raw_accounts_payable',
    curatedTable: 'curated.accounts_payable',
    pkColumns: ['company_code', 'document_number', 'fiscal_year', 'item'],
    columnMap: {
      'Company Code': 'company_code',
      'Document Number': 'document_number',
      'Fiscal Year': 'fiscal_year',
      'Posting Date': 'posting_date',
      'Vendor': 'vendor',
      'MSME': 'msme',
      'Purchasing Document': 'purchasing_document',
      'Item': 'item',
      'PO Document Type': 'po_document_type',
      'Internal Order': 'internal_order',
      'Debit/Credit': 'debit_credit',
      'Local Amount': 'local_amount',
      'Currency': 'currency'
    },
    dateColumns: ['posting_date'],
    numericColumns: ['local_amount'],
    intColumns: ['fiscal_year']
  },
  bank_report: {
    rawTable: 'raw.raw_bank_report',
    curatedTable: 'curated.bank_report',
    pkColumns: ['gl_account'],
    columnMap: {
      'G/L Account': 'gl_account',
      'Short Text': 'short_text',
      'Long Text': 'long_text',
      'Balance': 'balance'
    },
    dateColumns: [],
    numericColumns: ['balance'],
    intColumns: []
  },
  budget_report: {
    rawTable: 'raw.raw_budget_report',
    curatedTable: 'curated.budget_report',
    pkColumns: ['year', 'group_name', 'income_group', 'zmonth'],
    columnMap: {
      'Year': 'year',
      'GROUP': 'group_name',
      'INCOME_GROUP': 'income_group',
      'ZMONTH': 'zmonth',
      'BUDGET_CR': 'budget_cr'
    },
    dateColumns: [],
    numericColumns: ['budget_cr'],
    intColumns: ['year']
  },
  sales_register: {
    rawTable: 'raw.raw_sales_register',
    curatedTable: 'curated.sales_register',
    pkColumns: ['invoice_no'],
    columnMap: {
      'Invoice No': 'invoice_no',
      'Billing Type': 'billing_type',
      'Billing Type description': 'billing_type_description',
      'Invoice Date': 'invoice_date',
      'Bill To': 'bill_to',
      'Bill To Name': 'bill_to_name',
      'Fiscal Year': 'fiscal_year',
      ' Total': 'total'
    },
    dateColumns: ['invoice_date'],
    numericColumns: ['total'],
    intColumns: ['fiscal_year']
  }
};

const config = configs[reportType];
if (!config) {
  throw new Error(`Unknown report_type: ${reportType}. Valid types: ${Object.keys(configs).join(', ')}`);
}

const inputItem = $input.first();

// Rename binary field: n8n webhook receives it as 'file' (from multer),
// but the Spreadsheet File node expects 'data' by default
const newBinary = {};
if (inputItem.binary) {
  const keys = Object.keys(inputItem.binary);
  if (keys.length > 0) {
    newBinary.data = inputItem.binary[keys[0]];
  }
}

return [{
  json: {
    reportType,
    config,
    startedAt: new Date().toISOString()
  },
  binary: newBinary
}];

// Pure JS SHA256 - n8n sandbox blocks require('crypto')
function sha256(msg) {
  function rr(v, a) { return (v >>> a) | (v << (32 - a)); }
  const K = [0x428a2f98,0x71374491,0xb5c0fbcf,0xe9b5dba5,0x3956c25b,0x59f111f1,0x923f82a4,0xab1c5ed5,0xd807aa98,0x12835b01,0x243185be,0x550c7dc3,0x72be5d74,0x80deb1fe,0x9bdc06a7,0xc19bf174,0xe49b69c1,0xefbe4786,0x0fc19dc6,0x240ca1cc,0x2de92c6f,0x4a7484aa,0x5cb0a9dc,0x76f988da,0x983e5152,0xa831c66d,0xb00327c8,0xbf597fc7,0xc6e00bf3,0xd5a79147,0x06ca6351,0x14292967,0x27b70a85,0x2e1b2138,0x4d2c6dfc,0x53380d13,0x650a7354,0x766a0abb,0x81c2c92e,0x92722c85,0xa2bfe8a1,0xa81a664b,0xc24b8b70,0xc76c51a3,0xd192e819,0xd6990624,0xf40e3585,0x106aa070,0x19a4c116,0x1e376c08,0x2748774c,0x34b0bcb5,0x391c0cb3,0x4ed8aa4a,0x5b9cca4f,0x682e6ff3,0x748f82ee,0x78a5636f,0x84c87814,0x8cc70208,0x90befffa,0xa4506ceb,0xbef9a3f7,0xc67178f2];
  let H = [0x6a09e667,0xbb67ae85,0x3c6ef372,0xa54ff53a,0x510e527f,0x9b05688c,0x1f83d9ab,0x5be0cd19];
  const bytes = [];
  for (let i = 0; i < msg.length; i++) {
    const c = msg.charCodeAt(i);
    if (c < 128) bytes.push(c);
    else if (c < 2048) { bytes.push(192|(c>>6)); bytes.push(128|(c&63)); }
    else { bytes.push(224|(c>>12)); bytes.push(128|((c>>6)&63)); bytes.push(128|(c&63)); }
  }
  const bitLen = bytes.length * 8;
  bytes.push(0x80);
  while (bytes.length % 64 !== 56) bytes.push(0);
  for (let i = 56; i >= 0; i -= 8) bytes.push((bitLen / Math.pow(2, i)) & 0xff);
  for (let off = 0; off < bytes.length; off += 64) {
    const w = new Array(64);
    for (let i = 0; i < 16; i++) w[i] = (bytes[off+i*4]<<24)|(bytes[off+i*4+1]<<16)|(bytes[off+i*4+2]<<8)|bytes[off+i*4+3];
    for (let i = 16; i < 64; i++) {
      const s0 = rr(w[i-15],7)^rr(w[i-15],18)^(w[i-15]>>>3);
      const s1 = rr(w[i-2],17)^rr(w[i-2],19)^(w[i-2]>>>10);
      w[i] = (w[i-16]+s0+w[i-7]+s1)|0;
    }
    let [a,b,c,d,e,f,g,h] = H;
    for (let i = 0; i < 64; i++) {
      const S1 = rr(e,6)^rr(e,11)^rr(e,25);
      const ch = (e&f)^(~e&g);
      const t1 = (h+S1+ch+K[i]+w[i])|0;
      const S0 = rr(a,2)^rr(a,13)^rr(a,22);
      const maj = (a&b)^(a&c)^(b&c);
      const t2 = (S0+maj)|0;
      h=g;g=f;f=e;e=(d+t1)|0;d=c;c=b;b=a;a=(t1+t2)|0;
    }
    H=[H[0]+a|0,H[1]+b|0,H[2]+c|0,H[3]+d|0,H[4]+e|0,H[5]+f|0,H[6]+g|0,H[7]+h|0];
  }
  return H.map(v=>(v<0?v+0x100000000:v).toString(16).padStart(8,'0')).join('');
}

const configItem = $('Set Report Config').first().json;
const { config, reportType } = configItem;
const rows = $input.all();

// --- Helper functions ---
function escapeSql(val) {
  if (val === null || val === undefined) return 'NULL';
  const str = String(val);
  return "'" + str.replace(/'/g, "''") + "'";
}

function parseTrailingMinus(val) {
  if (val === null || val === undefined || val === '') return null;
  let str = String(val).trim();
  if (str === '') return null;
  if (str.endsWith('-')) {
    str = '-' + str.slice(0, -1);
  }
  str = str.replace(/,/g, '').trim();
  const num = parseFloat(str);
  return isNaN(num) ? null : num;
}

function parseDateYYYYMMDD(val) {
  if (!val) return null;
  const str = String(val).trim();
  if (str.length !== 8) return null;
  const y = str.substring(0, 4);
  const m = str.substring(4, 6);
  const d = str.substring(6, 8);
  return `${y}-${m}-${d}`;
}

// --- Normalize all rows ---
const normalizedRows = [];
for (const row of rows) {
  const mapped = {};
  for (const [csvCol, dbCol] of Object.entries(config.columnMap)) {
    let val = row.json[csvCol];
    if (val !== undefined && val !== null) {
      val = String(val).trim();
    }
    if (config.dateColumns.includes(dbCol)) {
      val = parseDateYYYYMMDD(val);
    } else if (config.numericColumns.includes(dbCol)) {
      val = parseTrailingMinus(val);
    } else if (config.intColumns.includes(dbCol)) {
      val = val ? parseInt(String(val).trim(), 10) : null;
      if (isNaN(val)) val = null;
    }
    mapped[dbCol] = (val === '' || val === undefined) ? null : val;
  }
  // Pure JS SHA256 hash for change detection
  const sortedKeys = Object.values(config.columnMap).sort();
  const hashInput = sortedKeys.map(k => String(mapped[k] ?? '')).join('|');
  mapped.row_hash = sha256(hashInput);
  normalizedRows.push(mapped);
}

// --- Build SQL with inline values (no parameterized queries) ---
const dbColumns = [...Object.values(config.columnMap), 'row_hash'];
const pkCols = config.pkColumns.join(', ');
const allCols = dbColumns.join(', ');

const updateCols = dbColumns
  .filter(c => !config.pkColumns.includes(c) && c !== 'row_hash')
  .map(c => `${c} = EXCLUDED.${c}`)
  .join(', ');

// Build VALUES clause with inline escaped values
const valueRows = [];
for (const row of normalizedRows) {
  const vals = dbColumns.map(col => {
    const v = row[col];
    if (v === null || v === undefined) return 'NULL';
    if (typeof v === 'number') return String(v);
    return escapeSql(v);
  });
  valueRows.push(`(${vals.join(', ')})`);
}

const valuesClause = valueRows.join(',\n    ');

const rawSql = `INSERT INTO ${config.rawTable} (${allCols})
    VALUES ${valuesClause}
    ON CONFLICT (${pkCols}) DO UPDATE SET ${updateCols}, row_hash = EXCLUDED.row_hash
    WHERE ${config.rawTable}.row_hash != EXCLUDED.row_hash`;

const curatedSql = `INSERT INTO ${config.curatedTable} (${allCols})
    VALUES ${valuesClause}
    ON CONFLICT (${pkCols}) DO UPDATE SET ${updateCols}, row_hash = EXCLUDED.row_hash
    WHERE ${config.curatedTable}.row_hash != EXCLUDED.row_hash`;

return [{
  json: {
    rawSql,
    curatedSql,
    rowCount: normalizedRows.length,
    reportType
  }
}];

const configItem = $('Set Report Config').first().json;
const { reportType, startedAt } = configItem;
const processNode = $('Process & Build SQL').first().json;
const rowCount = processNode.rowCount;
const completedAt = new Date().toISOString();
const duration = new Date(completedAt) - new Date(startedAt);

// Build audit SQL with inline values (no parameters)
function esc(val) {
  if (val === null || val === undefined) return 'NULL';
  return "'" + String(val).replace(/'/g, "''") + "'";
}

const auditSql = `INSERT INTO audit.upload_audit (report_type, file_name, rows_total, rows_inserted, rows_updated, rows_unchanged, upload_status, started_at, completed_at, duration_ms) VALUES (${esc(reportType)}, ${esc(reportType + '_upload')}, ${rowCount}, ${rowCount}, 0, 0, 'success', ${esc(startedAt)}, ${esc(completedAt)}, ${duration})`;

const response = {
  status: 'success',
  report_type: reportType,
  rows_processed: rowCount,
  duration_ms: duration,
  timestamp: completedAt
};

return [{
  json: {
    auditSql,
    response
  }
}];
